import (
	"fmt"
)

// maxLengthString returns the string with the maximum character length from the given slice.
func maxLengthString(strings []string) (string, error) {
	if len(strings) == 0 {
		return "", fmt.Errorf("input slice is empty")
	}

	var maxLength int
	var maxString string

	for _, str := range strings {
		if len(str) > maxLength {
			maxLength = len(str)
			maxString = str
		}
	}

	return maxString, nil
}

func main() {
	strings := []string{"apple", "banana", "cherry"}
	maxString, err := maxLengthString(strings)
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Println("String with maximum length:", maxString)
	}
}
```

In this code:

- We define a function `maxLengthString` that takes a slice of strings as input.
- We check if the input slice is empty and return an error if it is.
- We initialize `maxLength` to 0 and `maxString` to an empty string.
- We iterate over the input slice, updating `maxLength` and `maxString` whenever we find a string with a longer length.
- Finally, we return the string with the maximum length and no error.

Note that this function has a time complexity of O(n), where n is the number of strings in the input slice, because we need to iterate over the entire slice to find the maximum length string.

