// RaftNode represents a node in the Raft cluster
type RaftNode struct {
	ID        int
	State     State
	Term      int
	VotedFor  int
	Cluster   []int
	NextIndex map[int]int
	MatchIndex map[int]int
	Mu        sync.Mutex
}

// State represents the current state of a Raft node
type State int

const (
	Follower State = iota
	Candidate
	Leader
)

// ElectionTimeout represents the election timeout for a Raft node
type ElectionTimeout struct {
	Timeout time.Duration
}

// RequestVotePayload represents the payload for a RequestVote RPC
type RequestVotePayload struct {
	Term         int
	CandidateID  int
	LastLogIndex int
	LastLogTerm  int
}

// RequestVoteResponse represents the response for a RequestVote RPC
type RequestVoteResponse struct {
	Term        int
	VoteGranted bool
}

// RaftNode methods
func (n *RaftNode) startElection() {
	n.Mu.Lock()
	defer n.Mu.Unlock()

	n.State = Candidate
	n.Term++
	n.VotedFor = n.ID
	n.Cluster = append(n.Cluster, n.ID)
	n.NextIndex = make(map[int]int)
	n.MatchIndex = make(map[int]int)

	// Start election timer
	go n.startElectionTimer()
}

func (n *RaftNode) startElectionTimer() {
	electionTimeout := ElectionTimeout{Timeout: time.Duration(rand.Intn(1000)) * time.Millisecond}
	time.Sleep(electionTimeout.Timeout)
	n.Mu.Lock()
	defer n.Mu.Unlock()

	// If the node is still a candidate, start a new election
	if n.State == Candidate {
		n.startElection()
	}
}

func (n *RaftNode) voteForCandidate(candidateID int) bool {
	n.Mu.Lock()
	defer n.Mu.Unlock()

	// If the candidate's term is less than the current node's term, return false
	if candidateID != n.VotedFor && candidateID != n.ID && n.Term > 0 {
		return false
	}

	// If the candidate's term is greater than the current node's term, update the term and vote for the candidate
	if candidateID != n.VotedFor && candidateID != n.ID && candidateID != n.VotedFor && n.Term < candidateID {
		n.Term = candidateID
		n.VotedFor = candidateID
		return true
	}

	// If the candidate's term is equal to the current node's term, vote for the candidate
	if candidateID != n.VotedFor && candidateID != n.ID && n.Term == candidateID {
		n.VotedFor = candidateID
		return true
	}

	return false
}

func (n *RaftNode) handleRequestVoteRPC(term int, candidateID int, lastLogIndex int, lastLogTerm int) RequestVoteResponse {
	n.Mu.Lock()
	defer n.Mu.Unlock()

	// If the term is less than the current node's term, return false
	if term < n.Term {
		return RequestVoteResponse{Term: n.Term, VoteGranted: false}
	}

	// If the candidate's term is greater than the current node's term, update the term and vote for the candidate
	if term > n.Term {
		n.Term = term
		n.VotedFor = candidateID
		return RequestVoteResponse{Term: n.Term, VoteGranted: true}
	}

	// If the candidate's term is equal to the current node's term, vote for the candidate if the candidate's log is more up-to-date
	if term == n.Term && (lastLogIndex > n.NextIndex[candidateID] || lastLogTerm > n.NextIndex[candidateID]) {
		n.NextIndex[candidateID] = lastLogIndex
		n.MatchIndex[candidateID] = lastLogIndex
		n.VotedFor = candidateID
		return RequestVoteResponse{Term: n.Term, VoteGranted: true}
	}

	return RequestVoteResponse{Term: n.Term, VoteGranted: false}
}

