This parser supports a subset of Markdown syntax, including headers, bold text, links, and lists. It handles nested formatting and escapes HTML special characters in code blocks.

**Parser Code**
---------------

```typescript
interface MarkdownParserOptions {
  escapeHtml: boolean;
}

class MarkdownParser {
  private options: MarkdownParserOptions;

  constructor(options: MarkdownParserOptions = {}) {
    this.options = options;
  }

  private escapeHtml(str: string): string {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');
  }

  private parseHeader(header: string): string {
    const level = header.match(/^#{1,6}/)[0].length;
    const text = header.replace(/^#{1,6} /, '');
    return `<h${level}>${this.escapeHtml(text)}</h${level}>`;
  }

  private parseBold(text: string): string {
    return `<b>${this.escapeHtml(text)}</b>`;
  }

  private parseItalic(text: string): string {
    return `<i>${this.escapeHtml(text)}</i>`;
  }

  private parseLink(text: string): string {
    const match = text.match(/\[(.*?)\]\((.*?)\)/);
    if (match) {
      return `<a href="${this.escapeHtml(match[2])}">${this.escapeHtml(match[1])}</a>`;
    }
    return text;
  }

  private parseList(items: string[]): string {
    return `<ul>${items.map((item) => `<li>${this.parse(item)}</li>`).join('')}</ul>`;
  }

  private parseCodeBlock(code: string): string {
    return `<pre><code>${this.escapeHtml(code)}</code></pre>`;
  }

  private parseBlock(text: string): string {
    const lines = text.split('\n');
    if (lines.every((line) => line.trim() === '')) {
      return '<p></p>';
    }
    if (lines.every((line) => line.trim().startsWith('#'))) {
      return lines.map((line) => this.parseHeader(line)).join('\n');
    }
    if (lines.every((line) => line.trim().startsWith('*'))) {
      return this.parseList(lines.map((line) => line.trim().replace('*', '')));
    }
    if (lines.every((line) => line.trim().startsWith('```'))) {
      return this.parseCodeBlock(text.trim().replace(/^```.*\n/, ''));
    }
    return lines.map((line) => this.parse(line)).join('\n');
  }

  public parse(text: string): string {
    return this.parseBlock(text);
  }
}

export default MarkdownParser;
```

